export const CallbacksTableIDCell = React.memo(({rowData, callbackDropdown, onOpenTriggerDialog, onOpenUnlockDialog}) =>{
    const dropdownAnchorRef = React.useRef(null);
    const onOpenTab = useContext(OnOpenTabContext);
    const interactType = GetMythicSetting({setting_name: "interactType", default_value: "interact"})
    const [rowDataStatic, setRowDataStatic] = React.useState(rowData);
    React.useEffect( () => {
        let update = false;
        if(rowData.locked !== rowDataStatic.locked){
            update = true;
        }
        if(rowData.integrity_level !== rowDataStatic.integrity_level){
            update = true;
        }
        if(rowData.host !== rowDataStatic.host){
            update = true;
        }
        if(rowData.locked_operator !== rowDataStatic.locked_operator){
            update = true;
        }
        if(rowData.description !== rowDataStatic.description){
            update = true;
        }
        if(rowData.id !== rowDataStatic.id){
            update = true;
        }
        if(rowData.color !== rowDataStatic.color){
            update = true;
        }
        if(rowData.trigger_on_checkin_after_time !== rowDataStatic.trigger_on_checkin_after_time){
            update = true;
        }
        if(rowData.callbackports.length !== rowDataStatic.callbackports.length){
            update = true;
        }
        if(update){
            setRowDataStatic(rowData);
        }
    }, [rowData]);
    const proxyMessage = useCallback(() => {
        let message = [];
        for(let i = 0; i < rowDataStatic?.callbackports?.length || 0; i++){
            switch(rowDataStatic.callbackports[i].port_type){
                case "socks":
                    if(rowDataStatic.callbackports[i].username === ""){
                        message.push(`socks: ${rowDataStatic.callbackports[i].local_port}`);
                    } else {
                        message.push(`socks: ${rowDataStatic.callbackports[i].local_port}, ${rowDataStatic.callbackports[i].username}:${rowDataStatic.callbackports[i].password}`);
                    }
                    break;
                case "rpfwd":
                    if(rowDataStatic.callbackports[i].username === ""){
                        message.push(`rpfwd: ${rowDataStatic.callbackports[i].local_port}->${rowDataStatic.callbackports[i].remote_ip}:${rowDataStatic.callbackports[i].remote_port}`);
                    } else {
                        message.push(`pfwd: ${rowDataStatic.callbackports[i].local_port}->${rowDataStatic.callbackports[i].remote_ip}:${rowDataStatic.callbackports[i].remote_port}, ${rowDataStatic.callbackports[i].username}:${rowDataStatic.callbackports[i].password}`);
                    }
                    break;
                case "interactive":
                    message.push(`interactive: ${rowDataStatic.callbackports[i].local_port}`);
                    break;
            }
        }
        return message.join("\n");
    }, [rowDataStatic]);
    const handleDropdownToggle = (event) => {
        event.stopPropagation();
        callbackDropdown({rowDataStatic, event});
    };
    const handleOpenTriggerDialog = (event) => {
        event.stopPropagation();
        onOpenTriggerDialog?.(rowDataStatic);
    };
    const handleOpenUnlockDialog = (event) => {
        event.stopPropagation();
        onOpenUnlockDialog?.(rowDataStatic);
    };
    const localOnOpenTab = () => {
        onOpenTab({tabType: interactType, tabID: rowDataStatic.id + interactType, callbackID: rowDataStatic.id,  displayID: rowDataStatic.display_id});
    }
    let defaultInteractIcon = <KeyboardIcon fontSize="small" />;
    if(interactType === "interactSplit"){
        defaultInteractIcon = <VerticalSplitIcon fontSize="small" />;
    } else if(interactType === "interactConsole"){
        defaultInteractIcon = <TerminalIcon fontSize="small" />;
    }
    const highIntegrity = rowDataStatic.integrity_level >= 3;
    const lockOwner = rowDataStatic.locked_operator?.username || "unknown operator";

    return (
        <div id={`callbacksTableID${rowDataStatic.id}`} className="mythic-callback-interactCell">
            <MythicStyledTooltip title={`Open ${interactType === "interactSplit" ? "split" : interactType === "interactConsole" ? "console" : "tasking"} view${highIntegrity ? " - high integrity callback" : ""}`}>
                <IconButton
                    className={`mythic-callback-iconButton mythic-callback-interactButton${highIntegrity ? " mythic-action-tone mythic-tone-error" : ""}`}
                    onClick={(evt) => {evt.stopPropagation();localOnOpenTab()}}
                >
                    {defaultInteractIcon}
                </IconButton>
            </MythicStyledTooltip>
            <span className="mythic-callback-displayId">{rowDataStatic.display_id}</span>
            <IconButton
                className={`mythic-callback-iconButton mythic-callback-menuButton${highIntegrity ? " mythic-icon-tone mythic-action-tone-hover mythic-tone-error" : ""}`}
                aria-haspopup="menu"
                onClick={handleDropdownToggle}
                ref={dropdownAnchorRef}
            >
                <ArrowDropDownIcon fontSize="small" />
            </IconButton>
            {rowDataStatic.locked &&
                <MythicStyledTooltip title={`Locked by ${lockOwner}`}>
                    <button type="button"
                            className="mythic-callback-statusBadge mythic-callback-statusBadgeButton mythic-action-tone mythic-tone-warning"
                            aria-label={`Unlock callback ${rowDataStatic.display_id}`}
                            onClick={handleOpenUnlockDialog}>
                        <LockIcon fontSize="inherit" />
                    </button>
                </MythicStyledTooltip>
            }
            {rowDataStatic.trigger_on_checkin_after_time > 0 &&
                <MythicStyledTooltip title={`Alert on callback after no checkin for ${rowDataStatic.trigger_on_checkin_after_time} minutes`}>
                    <button type="button"
                            className="mythic-callback-statusBadge mythic-callback-statusBadgeButton mythic-action-tone mythic-tone-warning"
                            aria-label={`Adjust alert trigger for callback ${rowDataStatic.display_id}`}
                            onClick={handleOpenTriggerDialog}>
                        <NotificationsActiveTwoToneIcon fontSize="inherit" />
                    </button>
                </MythicStyledTooltip>
            }
            {rowDataStatic.callbackports.length > 0 &&
                <MythicStyledTooltip title={proxyMessage()}>
                    <span className="mythic-callback-statusBadge mythic-action-tone-hover mythic-tone-info">
                        <FontAwesomeIcon icon={faSocks} />
                    </span>
                </MythicStyledTooltip>
            }
        </div>
    )
},
    areEqual)
