const getTextSyntaxForFilename = (filename) => {
    if(!filename){
        return "html";
    }
    let extension = filename.split(".");
    if(extension.length > 1){
        extension = extension[extension.length - 1].toLowerCase();
        return textExtensionTypesToSyntax[extension] || "html";
    }
    return textExtensionTypesToSyntax[filename.toLowerCase()] || "html";
}

const DisplayText = ({agent_file_id, expand, filename, editable=false, fileMetaData}) => {
    const [content, setContent] = React.useState("");
    const [editedContent, setEditedContent] = React.useState("");
    const [loading, setLoading] = React.useState(true);
    const [loadError, setLoadError] = React.useState("");
    const [limitedPreviewWarning, setLimitedPreviewWarning] = React.useState(false);
    const [previewLoaded, setPreviewLoaded] = React.useState(false);
    const [saving, setSaving] = React.useState(false);
    const [previewFileString] = useMutation(previewFileQuery);
    const initialMode = React.useMemo(() => getTextSyntaxForFilename(filename), [filename]);
    React.useEffect( () => {
        let cancelled = false;
        const loadText = async () => {
            setLoading(true);
            setLoadError("");
            setPreviewLoaded(false);
            setLimitedPreviewWarning(false);
            setContent("");
            setEditedContent("");
            try{
                const {data} = await previewFileString({variables: {file_id: agent_file_id}});
                const previewData = data?.previewFile;
                if(cancelled){
                    return;
                }
                let previewText = "";
                if(previewData?.status !== "success"){
                    const errorMessage = previewData?.error || "Failed to preview file";
                    if(errorMessage === "EOF"){
                        setPreviewLoaded(true);
                    }else{
                        setLoadError(errorMessage);
                        snackActions.error(errorMessage);
                        return;
                    }
                }else{
                    setPreviewLoaded(true);
                    previewText = b64DecodeUnicode(previewData.contents || "");
                }
                if((previewData.size || 0) > MaxRenderSize){
                    setLimitedPreviewWarning(true);
                    setContent(previewText);
                    setEditedContent(previewText);
                    return;
                }
                const response = await mythicFetch('/direct/view/' + agent_file_id, {
                    headers: {
                        Authorization: `Bearer ${localStorage.getItem('access_token')}`,
                    }
                });
                if(cancelled){
                    return;
                }
                if(response.status !== 200){
                    setLoadError("Failed to fetch contents from Mythic");
                    snackActions.warning("Failed to fetch contents from Mythic");
                    setContent(previewText);
                    setEditedContent(previewText);
                    return;
                }
                const fullText = await response.text();
                if(cancelled){
                    return;
                }
                if(fullText.length > MaxRenderSize){
                    snackActions.warning("File too large (> 2MB), truncating the render");
                    setLimitedPreviewWarning(true);
                    const truncatedText = fullText.substring(0, MaxRenderSize);
                    setContent(truncatedText);
                    setEditedContent(truncatedText);
                    return;
                }
                setContent(fullText);
                setEditedContent(fullText);
            }catch(error){
                if(cancelled){
                    return;
                }
                const errorMessage = error.toString() === "TypeError: Failed to fetch" ?
                    "Unable to reach Mythic. Check the server, network, or certificate approval." :
                    "Error talking to server: " + error.toString();
                setLoadError(errorMessage);
                snackActions.warning(errorMessage);
                console.log("There was an error!", error);
            }finally{
                if(!cancelled){
                    setLoading(false);
                }
            }
        }
        if(agent_file_id){
            loadText();
        }
        return () => {
            cancelled = true;
        }
    }, [agent_file_id, previewFileString]);
    const canSave = editable &&
        previewLoaded &&
        !loading &&
        !loadError &&
        !limitedPreviewWarning &&
        fileMetaData?.complete !== false &&
        !fileMetaData?.deleted;
    const saveDisabledReason = !editable ? "Editing is not enabled for this file" :
        !previewLoaded ? "Text preview has not loaded successfully" :
        limitedPreviewWarning ? "Only a truncated preview is loaded" :
        fileMetaData?.complete === false ? "File is not completely uploaded" :
        fileMetaData?.deleted ? "Deleted files cannot be edited" :
        loadError ? loadError :
        saving ? "Saving file" :
        "";
    const onSave = async () => {
        if(!canSave || saving){
            if(saveDisabledReason){
                snackActions.warning(saveDisabledReason);
            }
            return;
        }
        setSaving(true);
        try{
            const newFile = new File([editedContent], filename || agent_file_id, {type: "text/plain;charset=utf-8"});
            const uploadResult = await UploadDirectFile(agent_file_id, newFile);
            if(uploadResult?.status === "success"){
                snackActions.success("Successfully saved file");
            }else if(uploadResult?.error){
                snackActions.error(uploadResult.error);
            }else{
                snackActions.error("Failed to save file");
            }
        }finally{
            setSaving(false);
        }
    }
    const toolbarActions = editable ? [
        <MythicStyledTooltip title={saveDisabledReason || "Save file"}>
            <span>
                <button
                    aria-label="Save file"
                    className="mythic-response-render-action-button mythic-action-tone mythic-tone-success"
                    disabled={!canSave || saving}
                    onClick={onSave}
                    type="button">
                    <SaveIcon fontSize="small" />
                </button>
            </span>
        </MythicStyledTooltip>
    ] : [];
    const toolbarNotice = limitedPreviewWarning ? (
        <MythicStyledTooltip title={"Only a truncated preview of this file is shown"}>
            <WarningOutlinedIcon style={{marginLeft: "5px"}} color={"warning"} />
        </MythicStyledTooltip>
    ) : null;
    return (
        <ResponseDisplayPlaintext
            plaintext={loading ? "Loading..." : content}
            expand={expand}
            initial_mode={initialMode}
            autoFormat={false}
            readOnly={!editable}
            toolbarTitle={"Text"}
            initial_show_options={true}
            toolbarActions={toolbarActions}
            toolbarNotice={toolbarNotice}
            enableCredentialCreation={!loading && previewLoaded}
            credentialMetadata={{
                agent_file_id,
                filemeta_id: fileMetaData?.id,
                filename: filename || fileMetaData?.filename,
            }}
            onChangeContent={setEditedContent}
        />
    )
}
const DisplayHex = ({agent_file_id, expand, fileMetaData}) => {
    const theme = useTheme();
    const [content, setContent] = React.useState("");
    const [previewFileString] = useMutation(previewFileQuery, {
        onCompleted: (previewData) => {
            if(previewData.previewFile.status === "success"){
                let data = atob(previewData.previewFile.contents);
                let newData = "";
                let stringData = "";
                for(let i = 0; i < data.length; i++){
                    let char = data[i].charCodeAt(0).toString(16);
                    if(char.length === 1){
                        newData += "0" + char;
                    }else{
                        newData += char;
                    }
                    if(data[i] === "\n"){
                        stringData += "\\n";
                    }else if(data[i] === "\r"){
                        stringData += "\\r";
                    }else{
                        stringData += data[i];
                    }
                    if((i+1) % 4 === 0){
                        newData += " ";
                    }
                    if((i+1) % 32 === 0){
                        newData += ": " + stringData + "\n";
                        stringData = "";
                    }
                }
                setContent(newData);
            }else{
                snackActions.error(previewData.previewFile.error)
            }
        },
        onError: (data) => {
            console.log(data);
            snackActions.error(data);
        }
    });
    React.useEffect( () => {
        previewFileString({variables: {file_id: agent_file_id}})
    }, [agent_file_id])
    return (
            <div style={{display: "flex", height: "100%", flexDirection: "column"}}>
                <div style={{display: "flex", flexGrow: 1, height: "100%"}}>
                    <AceEditor
                        mode="json"
                        theme={theme.palette.mode === "dark" ? "monokai" : "xcode"}
                        fontSize={14}
                        showGutter={true}
                        //onLoad={onLoad}
                        highlightActiveLine={false}
                        showPrintMargin={false}
                        value={content}
                        height={expand ? "100%": undefined}
                        maxLines={expand ? undefined : 20}
                        width={"100%"}
                        //autoScrollEditorIntoView={true}
                        minLines={2}
                        //maxLines={props.expand ? 50 : 20}
                        setOptions={{
                            showLineNumbers: true,
                            tabSize: 4,
                            useWorker: false
                        }}/>
                </div>
            </div>
);
}
const MAX_ROWS = 1000;
const DisplayDatabase = ({agent_file_id, expand, fileMetaData}) => {
    const theme = useTheme();
    const queryCountRef = React.useRef(1);
    const currentContentRef = React.useRef();
    const [selectedTab, setSelectedTab] = React.useState(0);
    const [sql, setSql] = React.useState(null);
    const [query, setQuery] = React.useState("select * from cookies;");
    const [results, setResults] = React.useState([]);
    const [loading, setLoading] = React.useState(true);
    const onChangeText = (data) => {
        setQuery(data);
    }
    const removeQuery = (event, index) => {
        event.stopPropagation();
        event.preventDefault();
        if(selectedTab === index){
            if(index !== 0){
                setSelectedTab(index-1);
            }
        }
        setResults(results.toSpliced(index, 1));
    }
    const onSubmitQuery = (event) => {
        if(event){
            event.stopPropagation();
            event.preventDefault();
        }
        if(sql){
            try{
                const result = sql.exec(query);
                //console.log(result);
                if(result.length > 0){
                    setResults([...results, {name: `Query: ${queryCountRef.current}`, query: query, results: result[0]}]);
                    setSelectedTab(queryCountRef.current - 1);
                    queryCountRef.current += 1;
                }
            }catch(e){
                console.log(e);
                snackActions.error(e.message);
            }
        } else {
            console.log(sql);
            snackActions.error("Failed to load as SQL Database");
        }
    }
    const onChangeTab = (_, v) => {
        const tabQuery = results[v]?.query;
        setQuery(tabQuery);
        setSelectedTab(v);
    }
    const onCopyToClipboard = (data) => {
        let result = copyStringToClipboard(data);
        if(result){
            snackActions.success("Copied text!");
        }else{
            snackActions.error("Failed to copy text");
        }
    }
    const onSaveOutputCSV = (result) => {
        const filteredData = result.results.values;
        let outputHeaders = "";
        let outputRow = "";
        outputHeaders = result.results.columns.join(",");
        for(let i = 0; i < filteredData.length; i++){
            outputRow += filteredData[i].join(",") + "\n"
        }
        onCopyToClipboard(outputHeaders + "\n" + outputRow);
    }
    const onSaveOutputPrettyPrint = (result) => {
        let tableData = result.results.values;
        if(tableData.length === 0){return}
        let outputHeaders = result.results.columns;
        let outputHeadersMaxLength = outputHeaders.reduce( (prev, cur) => {
            return [...prev,  cur.length]
        }, []);
        tableData.map( cur => {
            for(let i = 0; i < outputHeaders.length; i++){
                if(outputHeadersMaxLength[i] < String(cur[i]).length){
                    outputHeadersMaxLength[i] = String(cur[i]).length;
                }
            }
        });
        let allOutput = "";
        for(let i = 0; i < outputHeaders.length; i++){
            let remainingSpace = Math.max(0, outputHeadersMaxLength[i] - outputHeaders[i].length);
            allOutput += "  " + outputHeaders[i].toUpperCase() + " ".repeat(remainingSpace + 2);
        }
        allOutput += "\n";
        for(let i = 0; i < outputHeaders.length; i++){
            let remainingSpace = Math.max(0, outputHeadersMaxLength[i] - outputHeaders[i].length);
            allOutput += "  " + "-".repeat(outputHeaders[i].length) + " ".repeat(remainingSpace + 2);
        }
        allOutput += "\n";
        for(let i = 0; i < tableData.length; i++){
            for(let j = 0; j < outputHeaders.length; j++){
                let remainingSpace = Math.max(0, outputHeadersMaxLength[j] - String(tableData[i][j]).length);
                allOutput += "| " + String(tableData[i][j]) + " ".repeat(remainingSpace) + "  ";
            }
            allOutput += " |\n"
        }
        onCopyToClipboard(allOutput);
    }
    React.useEffect( () => {
        async function initialize(){
            const newSQL = await initSQLJS({locateFile: () => sqlWasm});
            mythicFetch('/direct/view/' + agent_file_id, {
                headers: {
                    Authorization: `Bearer ${localStorage.getItem('access_token')}`
                }
            }).then((response) => {
                if(response.status !== 200){
                    setLoading(false);
                    snackActions.warning("Failed to fetch contents from Mythic");
                    return;
                }
                response.arrayBuffer().then( data => {
                    const SQL = new newSQL.Database(new Uint8Array(data));
                    if(SQL){
                        setSql(SQL);
                    }
                    setLoading(false);
                }).catch(error => {
                        setLoading(false);
                        snackActions.warning("Error getting contents from server: " + error.toString());
                        console.log("Error trying to get json response", error, response);
                    });
            }).catch(error => {
                if(error.toString() === "TypeError: Failed to fetch"){
                    snackActions.warning("Unable to reach Mythic. Check the server, network, or certificate approval.");
                } else {
                    snackActions.warning("Error talking to server: " + error.toString());
                }
                setLoading(false);
                console.log("There was an error!", error);
            });
        }
        initialize();
    }, []);
    React.useEffect(() => {
        const handleKeyDown = (e) => {
            // Execute query on Ctrl+Enter or Cmd+Enter when in the SQL editor
            if (e.shiftKey && e.key === 'Enter') {
                onSubmitQuery(e);
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [onSubmitQuery]);
    return (
        <div style={{display: "flex", height: "100%", flexDirection: "column", width: "100%", position: "relative"}}>
            <Backdrop open={loading} onClick={()=>{setLoading(false);}} style={{zIndex: 2, position: "absolute"}}>
                <CircularProgress color="inherit" disableShrink  />
            </Backdrop>
            <div style={{display: "inline-flex", flexDirection: "row", alignItems: "center", borderBottom: "1px solid grey"}}>
                <AceEditor
                    className={"roundedBottomCorners"}
                    ref={currentContentRef}
                    mode={'sql'}
                    theme={theme.palette.mode === "dark" ? "monokai" : "xcode"}
                    fontSize={14}
                    showGutter={ true}
                    onChange={onChangeText}
                    highlightActiveLine={false}
                    showPrintMargin={false}
                    value={query}
                    height={"100%"}
                    maxLines={3}
                    width={"100%"}
                    wrapEnabled={true}
                    minLines={2}
                    setOptions={{
                        showLineNumbers: true,
                        tabSize: 4,
                        useWorker: false,
                        showInvisibles: false,
                    }}/>
                <Button color={"success"} variant={"contained"} onClick={onSubmitQuery} >Query</Button>
            </div>
            <TabContext style={{width: "100%", height: "100%", borderBottom: "1px solid grey", overflow: "auto"}} value={selectedTab}>
                <TabList onChange={onChangeTab} indicatorColor='secondary'
                         textColor='primary'
                         sx={{
                             '& .Mui-selected': {
                                 color: "unset !important"
                             }
                         }}>
                    {results.map((result, index) => (
                        <Tab key={result.query + index} style={{padding: 0, paddingLeft: "10px", paddingRight: "10px"}} label={
                            <div style={{display: "inline-block"}}>
                                {result.name}
                                <IconButton style={{padding: 0, marginLeft: "5px", marginRight: "5px", marginBottom: "5px"}}
                                            color={"error"}
                                            onClick={(e) => removeQuery(e, index)}>
                                    x
                                </IconButton>
                            </div>} value={index} className={selectedTab === index ? "selectedCallback" : ""} />
                    ))}
                </TabList>

                {results.map((result, index) => (
                    <div key={index} style={{display: selectedTab === index ? "flex" : "none",
                        width: "100%", height: "100%", overflow: "auto",
                        flexDirection: "column"}}>
                        {result?.results?.values?.length >= MAX_ROWS &&
                            <Paper key={"overflow" + index} style={{display: selectedTab === index ? "flex" : "none",
                                justifyContent: "center", hidden: selectedTab !== index}}>
                                <WarningOutlinedIcon color={"warning"}></WarningOutlinedIcon>
                                {"Output is truncated to first " + MAX_ROWS + " rows"}
                                <WarningOutlinedIcon color={"warning"}></WarningOutlinedIcon>
                            </Paper>
                        }
                        <div key={"output" + index} style={{display: selectedTab === index ? "flex" : "none", alignItems: "center", width: "100%"}}>
                            {"Save Output As: "}
                            <Button variant={"outlined"} style={{marginLeft: "10px"}} onClick={() => onSaveOutputCSV(result)} >CSV</Button>
                            <Button variant={"outlined"} style={{marginLeft: "10px"}} onClick={() => onSaveOutputPrettyPrint(result)} >Pretty Print</Button>
                        </div>
                        <TabPanel value={index} key={"tabpanel" + index}
                                  style={{padding: 0, height: "100%", width: "100%", overflow: "auto", position: "relative",
                                      display: selectedTab === index ? "flex" : "none",
                                      flexDirection: "column"}} >
                                <DisplayDatabaseResult result={result?.results} />
                        </TabPanel>
                    </div>
                ))}
            </TabContext>
        </div>
    )
}
const DisplayDatabaseResult = ({result}) => {
    const [columns, setColumns] = React.useState(result.columns);
    const [rows, setRows] = React.useState(result.values?.slice(0, MAX_ROWS));
    return (
        <TableContainer className="mythicElement" style={{height: "100%", position: "relative"}}>
        <Table stickyHeader style={{width: "100%", height: "100%", position: "absolute"}}>
            <TableHead >
                <TableRow>
                    {columns.map((column, index) => (
                        <TableCell key={"header" + index}>{column}</TableCell>
                    ))}
                </TableRow>
            </TableHead>
            <TableBody>
                {rows.map((row, index1) => (
                    <TableRow key={"row" + index1} hover>
                        {columns.map((_, index2) => (
                            <TableCell key={"row" + index1+ "cell" + index2}>
                                {row[index2]}
                            </TableCell>
                        ))}
                    </TableRow>
                ))}
            </TableBody>
        </Table>
        </TableContainer>
    )
}
