const createRowCells = ({row, rowIndex, headers, callback_id, task}) => {
  return headers.map((header, colIndex) => {
    const cellData = row[header.plaintext];
    const key = `${rowIndex}-${colIndex}-${header.plaintext}`;
    switch(header.type){
      case "string":
        return <ResponseDisplayTableStringCell key={key} cellData={cellData} rowData={row}/>
      case "size":
        return <ResponseDisplayTableSizeCell key={key} cellData={cellData} rowData={row}/>
      case "button":
        return <ResponseDisplayTableActionCell callback_id={callback_id} key={key} cellData={cellData} rowData={row} task={task}/>
      case "number":
        return <ResponseDisplayTableNumberCell callback_id={callback_id} key={key} cellData={cellData} rowData={row} />
      default:
        return <ResponseDisplayTableStringCell key={key} cellData={cellData} rowData={row}/>
    }
  })
}
export const ResponseDisplayTable = ({table, callback_id, expand, task}) =>{
  const rowHeight = GetComputedFontSize() + 15;
  const headerHeight = GetComputedFontSize() + 35;
  const maxHeight = 375;
  const [dataHeight, setDataHeight] = React.useState(maxHeight);
  const [allData, setAllData] = React.useState([]);
  const [selectedColumn, setSelectedColumn] = React.useState({});
  const [filterOptions, setFilterOptions] = React.useState({});
  const [openContextMenu, setOpenContextMenu] = React.useState(false);
  const columns = React.useMemo(
      () =>
          table?.headers?.reduce( (prev, cur) => {
            if(isGridColumnFilterActive(filterOptions[cur.plaintext])){
              return [...prev, {...cur, filtered: true}];
            }else{
              return [...prev, {...cur}];
            }
          }, []) || []
      , [filterOptions, table.headers]
  );
  const [sortData, setSortData] = React.useState({sortKey: null, sortType: null, sortDirection: "ASC"})
  const filterRow = (row) => {
    for(const [key,value] of Object.entries(filterOptions)){
      if(!gridValuePassesFilter(row[key]?.plaintext, value)){
        return true;
      }
    }
    return false;
  }
  const sortedData = React.useMemo(() => {

    const tmpData = [...allData].reduce( (prev, cur) => {
      if(filterRow(cur)){
        return [...prev];
      }else{
        return [...prev, cur];
      }
    }, []);
    if (sortData.sortKey === null || sortData.sortType === null) {
      return tmpData
    }
    if(sortData.sortType === "number" || sortData.sortType === "size"){
      tmpData.sort((a, b) => {
        if(a[sortData.sortKey]["plaintext"] === b[sortData.sortKey]["plaintext"]){
          return 0;
        }else if(a[sortData.sortKey]["plaintext"] === undefined || a[sortData.sortKey]["plaintext"] === null){
          return -1;
        }else if(b[sortData.sortKey]["plaintext"] === undefined || b[sortData.sortKey]["plaintext"] === null){
          return 1;
        }else{
          try{
            return parseInt(a[sortData.sortKey]["plaintext"]) > parseInt(b[sortData.sortKey]["plaintext"]) ? 1 : -1;
          }catch(error){
            console.log("failed to parse ints for sorting", a[sortData.sortKey]["plaintext"], b[sortData.sortKey]["plaintext"]);
            return a[sortData.sortKey]["plaintext"] > b[sortData.sortKey]["plaintext"] ? 1: -1;
          }
        }

      });
    }else if(sortData.sortType === "date"){
      tmpData.sort((a,b) => {
        if(a[sortData.sortKey]["plaintext"] ===  b[sortData.sortKey]["plaintext"]){
          return 0;
        }else if(a[sortData.sortKey]["plaintext"] === undefined || a[sortData.sortKey]["plaintext"] === null){
          return -1;
        }else if(b[sortData.sortKey]["plaintext"] === undefined || b[sortData.sortKey]["plaintext"] === null){
          return 1;
        }else{
          try{
            return (new Date(a[sortData.sortKey]["plaintext"])) > (new Date(b[sortData.sortKey]["plaintext"])) ? 1: -1
          }catch(error){
            console.log("failed to parse dates for sorting", a[sortData.sortKey]["plaintext"], b[sortData.sortKey]["plaintext"]);
            return a[sortData.sortKey]["plaintext"] > b[sortData.sortKey]["plaintext"] ? 1: -1;
          }
        }

      });
    }else{
      tmpData.sort( (a, b) => {
        if(a[sortData.sortKey]["plaintext"] === b[sortData.sortKey]["plaintext"]){
          return 0;
        }else if(a[sortData.sortKey]["plaintext"] === undefined || a[sortData.sortKey]["plaintext"] === null){
          return -1;
        }else if(b[sortData.sortKey]["plaintext"] === undefined || b[sortData.sortKey]["plaintext"] === null){
          return 1;
        } else {
          try{
            return a[sortData.sortKey]["plaintext"].localeCompare(b[sortData.sortKey]["plaintext"]);
          }catch(error){
            console.log("failed to localeCompare strings for sorting", a[sortData.sortKey]["plaintext"], b[sortData.sortKey]["plaintext"]);
            return a[sortData.sortKey]["plaintext"] > b[sortData.sortKey]["plaintext"] ? 1: -1;
          }
        }
      });
    }
    if(sortData.sortDirection === "DESC"){
      tmpData.reverse();
    }
    return tmpData;
  }, [allData, sortData, filterOptions]);
  const onClickHeader = (e, columnIndex) => {
    const column = table.headers[columnIndex];

    if(column.disableSort){
        return;
    }
    if (!column.plaintext) {
        setSortData({sortKey: null, sortType: null, sortDirection: "ASC"});
    }
    if (sortData.sortKey === column.plaintext) {
        if (sortData.sortDirection === 'ASC') {
            setSortData({...sortData, sortDirection: "DESC"});
        } else {
            setSortData({sortKey: null, sortType: null, sortDirection: "ASC"});
        }
    } else {
        setSortData({sortKey: column.plaintext, sortType: column.type, sortDirection: "ASC"});
    }
  };
  const gridData = React.useMemo(
    () => {
        return sortedData.map((row, rowIndex) => {
          return createRowCells({row, headers: table.headers, callback_id, rowIndex, task});
        });
    }, [sortedData, table?.headers, callback_id, task]
  );
    const onSubmitFilterOptions = (value) => {
        setFilterOptions(getUpdatedGridFilterOptions(filterOptions, selectedColumn.key, value));
    }

  const filterOutButtonsFromRowData = (data) => {
    let rowData = {};
    for(const key of Object.keys(data)){
      if(data[key]["plaintext"] !== undefined){
        rowData[key] = data[key]["plaintext"];
      }
    }
    return rowData;
  }
  const rowContextMenuOptions = [
    {
        name: 'Copy Row as JSON', icon: null,
        click: ({event, columnIndex, rowIndex, data}) => {
            const filteredData = filterOutButtonsFromRowData(data);
            onCopyToClipboard(JSON.stringify(filteredData, null, 2));
        }, type: "item"
    },
    {
      name: 'Copy Row as CSV', icon: null,
      click: ({event, columnIndex, rowIndex, data}) => {
          const filteredData = filterOutButtonsFromRowData(data);
          let outputHeaders = "";
          let outputRow = "";
          for(const key of Object.keys(filteredData)){
            if(outputHeaders === ""){
              outputHeaders += key;
            } else {
              outputHeaders += "," + key;
            }
            if(outputRow === ""){
              outputRow += filteredData[key];
            }else{
              outputRow += "," + filteredData[key];
            }
          }
          onCopyToClipboard(outputHeaders + "\n" + outputRow);
      },
      type: "item",
  },
    {
    name: 'Copy Row as TSV', icon: null,
    click: ({event, columnIndex, rowIndex, data}) => {
      const filteredData = filterOutButtonsFromRowData(data);
      let outputHeaders = "";
      let outputRow = "";
      for(const key of Object.keys(filteredData)){
        if(outputHeaders === ""){
          outputHeaders += key;
        } else {
          outputHeaders += "\t" + key;
        }
        if(outputRow === ""){
          outputRow += filteredData[key];
        }else{
          outputRow += "\t" + filteredData[key];
        }
      }
      onCopyToClipboard(outputHeaders + "\n" + outputRow);
    },
    type: "item",
},
    {
      name: 'Copy Cell', icon: null,
      click: ({event, columnIndex, rowIndex, data}) => {
        if(table.headers !== undefined && table.headers[columnIndex] !== undefined){
          let field = table.headers[columnIndex];
          if(field.plaintext !== undefined){ // column name
            if(data[field.plaintext].plaintext !== undefined){
              onCopyToClipboard(data[field.plaintext].plaintext);
            }
          }
        }
      }, type: "item"
    },
];
  const contextMenuOptions = [
    {
      name: 'Filter Column', type: "item", icon: null,
      click: ({event, columnIndex}) => {
        event.preventDefault();
        event.stopPropagation();
        if(table.headers[columnIndex].disableFilterMenu){
          snackActions.warning("Can't filter that column");
          return;
        }
        setSelectedColumn({
          "key": table.headers[columnIndex].plaintext,
          "name": table.headers[columnIndex].plaintext
        });
        setOpenContextMenu(true);
      }
    },
    {
      name: "Copy Table as JSON", type: "item", icon: null,
      click: ({event, columnIndex}) => {
        event.preventDefault();
        event.stopPropagation();
        let tableData = sortedData.map(d => filterOutButtonsFromRowData(d))
        onCopyToClipboard(JSON.stringify(tableData, null, 2));
      }
    },
    {
      name: "Copy Table as CSV", type: "item", icon: null,
      click: ({event, columnIndex}) => {
        event.preventDefault();
        event.stopPropagation();
        let tableData = sortedData.map(d => filterOutButtonsFromRowData(d));
        if(tableData.length === 0){return}
        let outputHeaders = "";
        let allOutput = "";

        for(let i = 0; i < tableData.length; i++){
          let outputRow = "";
          for(const key of Object.keys(tableData[i])){
            if(i === 0){
              if(outputHeaders === ""){
                outputHeaders += key;
              } else {
                outputHeaders += "," + key;
              }
            }
            if(outputRow === ""){
              outputRow += tableData[i][key];
            }else{
              outputRow += "," + tableData[i][key];
            }
          }
          allOutput += outputRow + "\n";
        }
        onCopyToClipboard(outputHeaders + "\n" + allOutput);
      }
    },
    {
      name: "Copy Table as TSV", type: "item", icon: null,
      click: ({event, columnIndex}) => {
        event.preventDefault();
        event.stopPropagation();
        let tableData = sortedData.map(d => filterOutButtonsFromRowData(d));
        if(tableData.length === 0){return}
        let outputHeaders = "";
        let allOutput = "";

        for(let i = 0; i < tableData.length; i++){
          let outputRow = "";
          for(const key of Object.keys(tableData[i])){
            if(i === 0){
              if(outputHeaders === ""){
                outputHeaders += key;
              } else {
                outputHeaders += "\t" + key;
              }
            }
            if(outputRow === ""){
              outputRow += tableData[i][key];
            }else{
              outputRow += "\t" + tableData[i][key];
            }
          }
          allOutput += outputRow + "\n";
        }
        onCopyToClipboard(outputHeaders + "\n" + allOutput);
      }
    },
    {
      name: "Copy Table as PrettyPrint Text", type: "item", icon: null,
      click: ({event, columnIndex}) => {
        event.preventDefault();
        event.stopPropagation();
        let tableData = sortedData.map(d => filterOutButtonsFromRowData(d));
        if(tableData.length === 0){return}
        let outputHeaders = Object.keys(tableData[0]);
        let outputHeadersMaxLength = outputHeaders.reduce( (prev, cur) => {
          return {...prev, [cur]: cur.length}
        }, {});
        tableData.map( cur => {
          for(let i = 0; i < outputHeaders.length; i++){
            if(outputHeadersMaxLength[outputHeaders[i]] < String(cur[outputHeaders[i]]).length){
              outputHeadersMaxLength[outputHeaders[i]] = String(cur[outputHeaders[i]]).length;
            }
          }
        });
        let allOutput = "";
        for(let i = 0; i < outputHeaders.length; i++){
          let remainingSpace = Math.max(0, outputHeadersMaxLength[outputHeaders[i]] - outputHeaders[i].length);
          allOutput += "  " + outputHeaders[i].toUpperCase() + " ".repeat(remainingSpace + 2);
        }
        allOutput += "\n";
        for(let i = 0; i < outputHeaders.length; i++){
          let remainingSpace = Math.max(0, outputHeadersMaxLength[outputHeaders[i]] - outputHeaders[i].length);
          allOutput += "  " + "-".repeat(outputHeaders[i].length) + " ".repeat(remainingSpace + 2);
        }
        allOutput += "\n";
        for(let i = 0; i < tableData.length; i++){
          for(let j = 0; j < outputHeaders.length; j++){
            let remainingSpace = Math.max(0, outputHeadersMaxLength[outputHeaders[j]] - String(tableData[i][outputHeaders[j]]).length);
            allOutput += "| " + String(tableData[i][outputHeaders[j]]) + " ".repeat(remainingSpace) + "  ";
          }
          allOutput += " |\n"
        }
        onCopyToClipboard(allOutput);
      }
    },
  ];
  
  useEffect( () => {
    setAllData(table.rows.map(getReadableBrowserScriptRow));
    setDataHeight(Math.min(maxHeight, (table.rows.length * rowHeight) + headerHeight));
  }, [table.rows])
  const sortColumn = table.headers.findIndex((column) => column.plaintext === sortData.sortKey);
  const tableStyle = React.useMemo( () => {
    return expand ? {flexGrow: 1,
          minHeight: gridData.length > 0 ? Math.min(maxHeight, dataHeight) : headerHeight,
          width: "100%", position: "relative"} :
        {height: dataHeight, position: "relative", width: "100%"}
  }, [expand, dataHeight, gridData]);
  return (
        <div className="mythic-response-table" style={{height: "100%", position: "relative"}}>
            {table?.title && (
                <MythicSectionHeader
                    dense
                    title={table.title}
                    sx={{mt: 0, mb: 0.5, minHeight: 40}}
                />
            )}

          <div className="mythic-response-table-grid" style={tableStyle}>
            <MythicResizableGrid
                  columns={columns}
                  sortIndicatorIndex={sortColumn}
                  sortDirection={sortData.sortDirection}
                  items={gridData}
                  widthMeasureKey={"plaintext"}
                  headerNameKey={"plaintext"}
                  onDoubleClickRow={doubleClickRow}
                  rowHeight={rowHeight}
                  onClickHeader={onClickHeader}
                  contextMenuOptions={contextMenuOptions}
                  rowContextMenuOptions={rowContextMenuOptions}
              />
            {openContextMenu &&
                <MythicDialog fullWidth={true} maxWidth="sm" open={openContextMenu}
                              onClose={()=>{setOpenContextMenu(false);}}
                              innerDialog={
                                  <GridColumnFilterDialog
                                      onSubmit={onSubmitFilterOptions}
                                      filterValue={filterOptions[selectedColumn.key]}
                                      selectedColumn={selectedColumn}
                                      onClose={() => {
                                          setOpenContextMenu(false);
                                      }}
                                    />
                            }
                />
            }
          </div>
        </div>
    
  )   
}
